void __run_on_exit(int ret)
{
    int n = __rt_nr_exit;
    while (n)
	--n, ((void(*)(int,void*))rt_exitfunc[n])(ret, rt_exitarg[n]);
}

int on_exit(void *function, void *arg)
{
    int n = __rt_nr_exit;
    if (n < 32) {
	rt_exitfunc[n] = function;
	rt_exitarg[n] = arg;
        __rt_nr_exit = n + 1;
        return 0;
    }
    return 1;
}

